// Descarta spam y normaliza. Devolver [] corta el flujo sin avisar al bot.
const b = $input.first().json.body ?? {};

// 1. Honeypot: 'website' es un campo invisible en el form; solo lo rellenan los bots.
//    OJO: 'company' es la Empresa REAL del formulario, no es el cebo.
if ((b.website ?? '') !== '') return [];

// 2. Rellenado en menos de 3s: nadie escribe tan rapido.
if (Number(b.elapsed ?? 0) < 3) return [];

const clean = (v, max) => String(v ?? '').trim().slice(0, max);
const name = clean(b.name, 80);
const email = clean(b.email, 120);
const message = clean(b.message, 2000);

if (!name || !email || !message) return [];
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) return [];

return [{ json: {
  name,
  email,
  message,
  company: clean(b.company, 80),
  topic: clean(b.topic, 20) || 'otro',
  lang: clean(b.lang, 5),
  page: clean(b.page, 120),
} }];
